use std::ptr;
use std::mem::{size_of, MaybeUninit};

struct RawMatrix {
    data: *mut f32,
    rows: usize,
    cols: usize,
}

impl RawMatrix {
    fn new(rows: usize, cols: usize) -> Self {
        let size = rows.wrapping_mul(cols);
        unsafe {
            let layout = std::alloc::Layout::array::<f32>(size).expect("Failed to allocate memory for matrix");
            let raw_ptr = std::alloc::alloc(layout) as *mut f32;
            std::ptr::write(raw_ptr, 0.0);
            RawMatrix { data: raw_ptr, rows, cols }
        }
    }

    fn set_value(&mut self, row: usize, col: usize, value: f32) {
        let index = row.wrapping_mul(self.cols).wrapping_add(col);
        unsafe { ptr::write(self.data.add(index), value); }
    }

    fn get_value(&self, row: usize, col: usize) -> f32 {
        let index = row.wrapping_mul(self.cols).wrapping_add(col);
        unsafe { ptr::read(self.data.add(index)) }
    }

    fn process_row(&mut self, row: usize) -> f32 {
        let mut sum = 0.0;
        for col in 0..self.cols {
            let value = self.get_value(row, col);
            sum += value * (col as f32).sqrt();
        }
        sum
    }
}

fn main() {
    const R: usize = 5;
    const C: usize = 7;
    let mut matrix = RawMatrix::new(R, C);

    matrix.set_value(0, 0, 1.0);
    matrix.set_value(4, 6, 5.5);

    let result = matrix.process_row(2);

    println!("Processed Row Sum: {}", result);
}

use std::collections::VecDeque;

struct TlsRecord {
    sequence_number: u64,
    payload_len: usize,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut records_queue: VecDeque<TlsRecord> = VecDeque::new();
    records_queue.push_back(TlsRecord { sequence_number: 100, payload_len: 256 });
    records_queue.push_back(TlsRecord { sequence_number: 101, payload_len: 512 });

    let last_record = records_queue.pop_back().unwrap();
    println!("Processed record with sequence {}", last_record.sequence_number);

    records_queue.push_front(TlsRecord { sequence_number: 99, payload_len: 128 });

    if let Some(first_record) = records_queue.pop_front() {
        println!("Next up is record with sequence {}", first_record.sequence_number);
    }

    Ok(())
}

use std::collections::VecDeque;
use std::fmt::{self, Display, Formatter};
use std::error::Error;

#[derive(Debug)]
struct JobHandle {
    id: u32,
    data_size: usize,
}
impl Display for JobHandle {
    fn fmt(&self, f: &mut Formatter<'_>) -> Result<(), std::fmt::Error> {
        write!(f, "Job {} ({} bytes)", self.id, self.data_size)
    }
}
impl Error for JobHandle {}

struct WorkerPool {
    available_handles: VecDeque<JobHandle>,
    next_job_id: u32,
}
impl WorkerPool {
    fn new() -> Self {
        WorkerPool {
            available_handles: VecDeque::new(),
            next_job_id: 1,
        }
    }

    fn allocate_workload(&mut self, initial_count: u32) -> JobHandle {
        let handle = JobHandle { id: self.next_job_id, data_size: (initial_count as usize).saturating_mul(1024) };
        self.next_job_id += 1;
        handle
    }

    fn release_workload(&mut self, handle: JobHandle) {
        println!("Releasing resource for: {}", handle);
        self.available_handles.push_back(handle);
    }

    fn execute_job(&mut self, job_data: Vec<u8>) -> Result<(), Box<dyn Error>> {
        let handle = match self.available_handles.pop_front() {
            Some(h) => h,
            None => return Err("No available worker handles to process data".into()),
        };
        println!("Executing job using handle: {}", handle);
        if job_data.len() < 1024 * 5 {
            return Err("Job data too small for required minimum throughput".into());
        }
        println!("Successfully processed {} bytes.", job_data.len());
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut pool = WorkerPool::new();

    let initial_job = pool.allocate_workload(10);
    println!("System initialized with: {}", initial_job);

    let job_data_ok = vec![0u8; 1024 * 5];
    pool.execute_job(job_data_ok)?;

    let job_data_fail = vec![0u8; 500];
    if let Err(e) = pool.execute_job(job_data_fail) {
        println!("Caught expected error during execution: {}", e);
    }

    let unused_handle = JobHandle { id: 99, data_size: 0 };
    pool.release_workload(unused_handle);

    Ok(())
}

use std::fs::File;
use std::io::{self, Write};

struct DataContainer {
    text_data: String,
    count_data: u32,
}
impl DataContainer {
    fn new(text: &str, count: u32) -> Self {
        DataContainer { text_data: text.to_string(), count_data: count }
    }

    fn serialize(&self) -> io::Result<Vec<u8>> {
        let mut buffer = Vec::new();

        write!(&mut buffer, "TEXT_START:{}n", &self.text_data).unwrap();
        write!(&mut buffer, "COUNT_START:{}n", self.count_data).unwrap();
        write!(&mut buffer, "DATA_ENDn").unwrap();
        Ok(buffer)
    }

    fn save_to_file(&self, path: &str) -> io::Result<()> {
        let serialized = self.serialize()?;
        let mut file = File::create(path)?;
        file.write_all(&serialized)?; 
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let item1 = DataContainer::new("Learning Rust is fun", 42);
    item1.save_to_file("data_output.bin")?;
    println!("Successfully wrote sample data to data_output.bin");
    Ok(())
}

use std::collections::VecDeque;

struct UnitPathCache {
    cache: VecDeque<i32>,
}

impl UnitPathCache {
    fn new() -> Self {
        UnitPathCache { 
            cache: VecDeque::new()
        }
    }

    fn add_point(&mut self, point: i32) {
        self.cache.push_back(point);
    }

    fn remove_oldest_point(&mut self) -> Option<i32> {
        self.cache.pop_front()
    }

    fn get_current_path(&self) -> std::vec::IntoIter<i32> {
        self.cache.iter().cloned().collect::<Vec<_>>().into_iter()
    }
}

fn main() {
    let mut path_manager = UnitPathCache::new();
    path_manager.add_point(10);
    path_manager.add_point(25);
    path_manager.add_point(30);

    println!("Initial path points:");
    for point in path_manager.get_current_path() {
        print!("{}n", point);
    }
    println!("");

    let removed = path_manager.remove_oldest_point();
    if let Some(point) = removed {
        println!("Removed oldest point: {}", point);
    }

    path_manager.add_point(50);

    println!("Updated path points:");
    for point in path_manager.get_current_path() {
        print!("{}n", point);
    }
    println!("");
}
